// Error-trigger payload has two shapes: execution errors carry
// { execution: { id, url, error, lastNodeExecuted, mode }, workflow },
// trigger-activation failures carry { trigger: { error, mode }, workflow }.
const data = $input.first().json;
const wf = data.workflow ?? {};
const exec = data.execution ?? {};
const err = exec.error ?? data.trigger?.error ?? {};

const wfName = wf.name ?? 'unknown workflow';
const wfId = wf.id ?? 'unknown';
const failedNode = err.node?.name ?? exec.lastNodeExecuted ?? 'unknown node';
const message = err.message ?? 'no error message';
const execUrl = exec.url ?? '';
const now = Date.now();

// Per-source-workflow throttle so a broken schedule poller alerts once
// per window instead of once per tick. Static data persists across
// executions of this workflow only.
const throttleMin = Number($env.ERROR_ALERT_THROTTLE_MIN ?? 60);
const staticData = $getWorkflowStaticData('global');
staticData.lastAlertAt = staticData.lastAlertAt ?? {};
const lastAt = Number(staticData.lastAlertAt[wfId] ?? 0);
const throttled = now - lastAt < throttleMin * 60_000;
if (!throttled) {
  staticData.lastAlertAt[wfId] = now;
}

const recipient = $env.ERROR_ALERT_RECIPIENT || $env.MAILBOX_OPERATOR_EMAIL || '';

const escapeHtml = (s) => String(s).replace(/[&<>"]/g, (c) => ({ '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;' }[c]));
const html = [
  '<h3>MailBOX workflow error</h3>',
  `<p><b>Workflow:</b> ${escapeHtml(wfName)}<br/>`,
  `<b>Failed node:</b> ${escapeHtml(failedNode)}<br/>`,
  `<b>Time:</b> ${new Date(now).toISOString()}</p>`,
  `<p><b>Error:</b><br/><code>${escapeHtml(message)}</code></p>`,
  execUrl ? `<p><a href="${escapeHtml(execUrl)}">Open execution</a></p>` : '',
  `<p style="color:#888">Further errors from this workflow are muted for ${throttleMin} min.</p>`,
].join('\n');

return [{
  json: {
    should_send: Boolean(recipient) && !throttled,
    throttled,
    recipient,
    subject: `[MailBOX] Workflow error: ${wfName} — ${failedNode}`,
    html,
  },
}];
